365	#### `tryCheckBlocked()` — New Crawl Phase
366	
367	```typescript
368	async function tryCheckBlocked(): Promise<CrawlResult | null> {
369	  const rigs = await rigsBook.find({
370	    where: [['status', 'in', ['running', 'blocked']]],
371	  });
372	
373	  for (const rig of rigs) {
374	    for (const engine of rig.engines) {
375	      if (engine.status !== 'blocked' || !engine.block) continue;
376	
377	      const blockType = blockTypeRegistry.get(engine.block.type);
378	      if (!blockType) continue; // Type was unregistered after block was created; skip
379	
380	      // Poll interval throttle
381	      if (blockType.pollIntervalMs && engine.block.lastCheckedAt) {
382	        const elapsed = Date.now() - new Date(engine.block.lastCheckedAt).getTime();
383	        if (elapsed < blockType.pollIntervalMs) continue;
384	      }
385	
386	      let cleared: boolean;
387	      try {
388	        cleared = await blockType.check(engine.block.condition);
389	      } catch (err) {
390	        // Log warning, skip — engine stays blocked, retry next cycle
391	        console.warn(
392	          `Block checker "${engine.block.type}" threw for engine "${engine.id}" in rig "${rig.id}":`,
393	          err,
394	        );
395	        continue;
396	      }
397	
398	      if (!cleared) {
399	        // Update lastCheckedAt
400	        const now = new Date().toISOString();
401	        const updatedEngines = rig.engines.map((e) =>
402	          e.id === engine.id
403	            ? { ...e, block: { ...e.block!, lastCheckedAt: now } }
404	            : e,
405	        );
406	        await rigsBook.patch(rig.id, { engines: updatedEngines });
407	        return null; // One action per crawl — wrote lastCheckedAt
408	      }
409	
410	      // Cleared — store block record in memory for priorBlock, then transition
411	      const priorBlockRecord = engine.block;
412	      pendingPriorBlocks.set(`${rig.id}:${engine.id}`, priorBlockRecord);
413	
414	      const updatedEngines = rig.engines.map((e) =>
415	        e.id === engine.id
416	          ? { ...e, status: 'pending' as const, block: undefined }
417	          : e,
418	      );
419	
420	      // Restore rig to running if it was blocked
421	      const rigStatus = rig.status === 'blocked' ? 'running' : rig.status;
422	
423	      await rigsBook.patch(rig.id, {
424	        engines: updatedEngines,
425	        status: rigStatus,
426	      });
427	
428	      return { action: 'engine-unblocked', rigId: rig.id, engineId: engine.id };
429	    }
430	  }
431	  return null;
432	}
433	```
434	
435	**In-memory prior block storage:** Add a `Map<string, BlockRecord>` at module scope inside `createSpider()`:
436	
437	```typescript
438	const pendingPriorBlocks = new Map<string, BlockRecord>();
439	```
440	
441	Key format: `"rigId:engineId"`. Written when an engine is unblocked (via checker or `resume()`). Read and deleted in `tryRun()` when building `EngineRunContext`.
