1	/**
2	 * The Spider — rig execution engine apparatus.
3	 *
4	 * The Spider drives writ-to-completion by managing rigs: ordered pipelines
5	 * of engine instances. Each crawl() call performs one unit of work:
6	 *
7	 *   collect > checkBlocked > run > spawn   (priority order)
8	 *
9	 * collect      — check running engines for terminal session results
10	 * checkBlocked — poll registered block type checkers; unblock engines when cleared
11	 * run          — execute the next pending engine (clockwork inline, quick → launch)
12	 * spawn        — create a new rig for a ready writ with no existing rig
13	 *
14	 * CDC on the rigs book (Phase 1 cascade) transitions the associated writ
15	 * when a rig reaches a terminal state (completed or failed).
16	 * The blocked status does NOT trigger the CDC handler.
17	 *
18	 * See: docs/architecture/apparatus/spider.md
19	 */
20	
21	import type { Plugin, StartupContext, LoadedPlugin } from '@shardworks/nexus-core';
22	import { guild, generateId, isLoadedKit, isLoadedApparatus } from '@shardworks/nexus-core';
23	import type { StacksApi, Book, ReadOnlyBook, WhereClause } from '@shardworks/stacks-apparatus';
24	import type { ClerkApi, WritDoc } from '@shardworks/clerk-apparatus';
25	import type { FabricatorApi } from '@shardworks/fabricator-apparatus';
26	import type { SessionDoc } from '@shardworks/animator-apparatus';
27	
28	import type {
29	  RigDoc,
30	  RigFilters,
31	  EngineInstance,
32	  SpiderApi,
33	  CrawlResult,
34	  SpiderConfig,
35	  BlockRecord,
36	  BlockType,
37	} from './types.ts';
38	
39	import {
40	  draftEngine,
41	  implementEngine,
42	  reviewEngine,
43	  reviseEngine,
44	  sealEngine,
45	} from './engines/index.ts';
46	
47	import {
48	  writStatusBlockType,
49	  scheduledTimeBlockType,
50	  bookUpdatedBlockType,
51	} from './block-types/index.ts';
52	
53	import {
54	  crawlOneTool,
55	  crawlContinualTool,
56	  rigShowTool,
57	  rigListTool,
58	  rigForWritTool,
59	  rigResumeTool,
60	} from './tools/index.ts';
61	
62	// ── Helpers ────────────────────────────────────────────────────────────
63	
64	/**
65	 * Check whether a value is JSON-serializable.
66	 * Non-serializable yields cause engine failure — the Stacks cannot store them.
67	 */
68	function isJsonSerializable(value: unknown): boolean {
69	  try {
70	    JSON.stringify(value);
71	    return true;
72	  } catch {
73	    return false;
74	  }
75	}
76	
77	/**
78	 * Build the upstream yields map for a rig: all completed engine yields
79	 * keyed by engine id. Passed as context.upstream to the engine's run().
80	 */
81	function buildUpstreamMap(rig: RigDoc): Record<string, unknown> {
82	  const upstream: Record<string, unknown> = {};
83	  for (const engine of rig.engines) {
84	    if (engine.status === 'completed' && engine.yields !== undefined) {
85	      upstream[engine.id] = engine.yields;
86	    }
87	  }
88	  return upstream;
89	}
90	
91	/**
92	 * Find the first pending engine whose entire upstream is completed.
93	 * Returns null if no runnable engine exists.
94	 */
95	function findRunnableEngine(rig: RigDoc): EngineInstance | null {
96	  for (const engine of rig.engines) {
97	    if (engine.status !== 'pending') continue;
98	    const allUpstreamDone = engine.upstream.every((upstreamId) => {
99	      const dep = rig.engines.find((e) => e.id === upstreamId);
100	      return dep?.status === 'completed';
101	    });
102	    if (allUpstreamDone) return engine;
103	  }
104	  return null;
105	}
106	
107	/**
108	 * Determine whether a rig should enter the blocked state.
109	 *
110	 * A rig is blocked when:
111	 * - No engine is currently running
112	 * - No engine is runnable (pending with all upstream completed)
113	 * - At least one engine is blocked
114	 */
115	function isRigBlocked(engines: EngineInstance[]): boolean {
116	  const hasRunning = engines.some((e) => e.status === 'running');
117	  if (hasRunning) return false;
118	  const hasBlocked = engines.some((e) => e.status === 'blocked');
119	  if (!hasBlocked) return false;
120	  // Check runnability by constructing a minimal RigDoc-like object
121	  const syntheticRig = { engines } as RigDoc;
122	  return findRunnableEngine(syntheticRig) === null;
123	}
124	
125	/**
126	 * Produce the five-engine static pipeline for a writ.
127	 * Each engine receives only the givens it needs.
128	 * Upstream yields arrive via context.upstream at run time.
129	 */
130	function buildStaticEngines(writ: WritDoc, config: SpiderConfig): EngineInstance[] {
131	  const role = config.role ?? 'artificer';
132	  const reviewGivens: Record<string, unknown> = {
133	    writ,
134	    role: 'reviewer',
135	    ...(config.buildCommand !== undefined ? { buildCommand: config.buildCommand } : {}),
136	    ...(config.testCommand !== undefined ? { testCommand: config.testCommand } : {}),
137	  };
138	
139	  return [
140	    { id: 'draft',     designId: 'draft',     status: 'pending', upstream: [],           givensSpec: { writ } },
141	    { id: 'implement', designId: 'implement', status: 'pending', upstream: ['draft'],     givensSpec: { writ, role } },
142	    { id: 'review',    designId: 'review',    status: 'pending', upstream: ['implement'], givensSpec: reviewGivens },
143	    { id: 'revise',    designId: 'revise',    status: 'pending', upstream: ['review'],    givensSpec: { writ, role } },
144	    { id: 'seal',      designId: 'seal',      status: 'pending', upstream: ['revise'],    givensSpec: {} },
145	  ];
146	}
147	
148	// ── Block type type guard ──────────────────────────────────────────────
149	
150	function isBlockType(value: unknown): value is BlockType {
151	  return (
152	    typeof value === 'object' &&
153	    value !== null &&
154	    typeof (value as Record<string, unknown>).id === 'string' &&
155	    typeof (value as Record<string, unknown>).check === 'function'
156	  );
157	}
158	
159	// ── Block type registry ────────────────────────────────────────────────
160	
161	class BlockTypeRegistry {
162	  private readonly types = new Map<string, BlockType>();
163	
164	  register(plugin: LoadedPlugin): void {
165	    if (isLoadedKit(plugin)) {
166	      this.registerFromKit(plugin.kit);
167	    } else if (isLoadedApparatus(plugin)) {
168	      if (plugin.apparatus.supportKit) {
169	        this.registerFromKit(plugin.apparatus.supportKit);
170	      }
171	    }
172	  }
173	
174	  private registerFromKit(kit: Record<string, unknown>): void {
175	    const raw = kit.blockTypes;
176	    if (typeof raw !== 'object' || raw === null) return;
177	    for (const value of Object.values(raw as Record<string, unknown>)) {
178	      if (isBlockType(value)) {
179	        this.types.set(value.id, value);
180	      }
181	    }
182	  }
183	
184	  get(id: string): BlockType | undefined {
185	    return this.types.get(id);
186	  }
187	}
188	
189	// ── Apparatus factory ──────────────────────────────────────────────────
190	
191	export function createSpider(): Plugin {
192	  let rigsBook: Book<RigDoc>;
193	  let sessionsBook: ReadOnlyBook<SessionDoc>;
194	  let writsBook: ReadOnlyBook<WritDoc>;
195	  let clerk: ClerkApi;
196	  let fabricator: FabricatorApi;
197	  let spiderConfig: SpiderConfig = {};
198	
199	  const blockTypeRegistry = new BlockTypeRegistry();
200	
201	  /**
202	   * In-memory store for block records that have been cleared.
203	   * Key: "rigId:engineId". Written when an engine is unblocked (via checker or resume()).
204	   * Read and deleted in tryRun() when building EngineRunContext.
205	   */
206	  const pendingPriorBlocks = new Map<string, BlockRecord>();
207	
208	  // ── Internal crawl operations ─────────────────────────────────────
209	
210	  /**
211	   * Mark an engine failed and propagate failure to the rig (same update).
212	   * Cancels all pending and blocked engines.
213	   */
214	  async function failEngine(
215	    rig: RigDoc,
216	    engineId: string,
217	    errorMessage: string,
218	  ): Promise<void> {
219	    const now = new Date().toISOString();
220	    const updatedEngines = rig.engines.map((e) => {
221	      if (e.id === engineId) {
222	        return { ...e, status: 'failed' as const, error: errorMessage, completedAt: now };
223	      }
224	      if (e.status === 'pending' || e.status === 'blocked') {
225	        return { ...e, status: 'cancelled' as const, block: undefined };
226	      }
227	      return e;
228	    });
229	    await rigsBook.patch(rig.id, {
230	      engines: updatedEngines,
231	      status: 'failed',
232	    });
233	  }
234	
235	  /**
236	   * Phase 1 — collect.
237	   *
238	   * Find the first running engine with a sessionId whose session has
239	   * reached a terminal state. Populate yields and advance the engine
240	   * (and possibly the rig) to completed or failed.
241	   *
242	   * After collecting a completed engine, check whether the rig has
243	   * become blocked (no running engines, no runnable engines, some blocked).
244	   */
245	  async function tryCollect(): Promise<CrawlResult | null> {
246	    const runningRigs = await rigsBook.find({ where: [['status', '=', 'running']] });
247	    for (const rig of runningRigs) {
248	      for (const engine of rig.engines) {
249	        if (engine.status !== 'running' || !engine.sessionId) continue;
250	
251	        const session = await sessionsBook.get(engine.sessionId);
252	        if (!session || session.status === 'running') continue;
253	
254	        // Terminal session found — collect.
255	        const now = new Date().toISOString();
256	
257	        if (session.status === 'failed' || session.status === 'timeout') {
258	          await failEngine(rig, engine.id, session.error ?? `Session ${session.status}`);
259	          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
260	        }
261	
262	        // Completed session — assemble yields via engine's collect() or generic default.
263	        const design = fabricator.getEngineDesign(engine.designId);
264	        let yields: unknown;
265	        if (design?.collect) {
266	          const givens = { ...engine.givensSpec };
267	          const upstream = buildUpstreamMap(rig);
268	          const context = { engineId: engine.id, upstream };
269	          yields = await design.collect(engine.sessionId!, givens, context);
270	        } else {
271	          yields = {
272	            sessionId: session.id,
273	            sessionStatus: session.status,
274	            ...(session.output !== undefined ? { output: session.output } : {}),
275	          };
276	        }
277	
278	        if (!isJsonSerializable(yields)) {
279	          await failEngine(rig, engine.id, 'Session yields are not JSON-serializable');
280	          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
281	        }
282	
283	        const updatedEngines = rig.engines.map((e) =>
284	          e.id === engine.id
285	            ? { ...e, status: 'completed' as const, yields, completedAt: now }
286	            : e,
287	        );
288	
289	        const allCompleted = updatedEngines.every((e) => e.status === 'completed');
290	
291	        if (allCompleted) {
292	          await rigsBook.patch(rig.id, { engines: updatedEngines, status: 'completed' });
293	          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'completed' };
294	        }
295	
296	        // Check whether completing this engine has caused the rig to become blocked
297	        if (isRigBlocked(updatedEngines)) {
298	          await rigsBook.patch(rig.id, { engines: updatedEngines, status: 'blocked' });
299	          return { action: 'rig-blocked', rigId: rig.id, writId: rig.writId };
300	        }
301	
302	        await rigsBook.patch(rig.id, { engines: updatedEngines, status: 'running' });
303	        return { action: 'engine-completed', rigId: rig.id, engineId: engine.id };
304	      }
305	    }
306	    return null;
307	  }
308	
309	  /**
310	   * Phase 2 — checkBlocked.
311	   *
312	   * Query rigs with status 'running' or 'blocked'. For each blocked engine,
313	   * run the registered checker (respecting pollIntervalMs). If cleared,
314	   * transition the engine back to pending and restore the rig to running.
315	   * If not cleared, update lastCheckedAt and continue to the next engine.
316	   */
317	  async function tryCheckBlocked(): Promise<CrawlResult | null> {
318	    // Fetch both running rigs (may have blocked engines) and blocked rigs
319	    const runningRigs = await rigsBook.find({ where: [['status', '=', 'running']] });
320	    const blockedRigs = await rigsBook.find({ where: [['status', '=', 'blocked']] });
321	    const rigs = [...runningRigs, ...blockedRigs];
322	
323	    for (const rig of rigs) {
324	      for (const engine of rig.engines) {
325	        if (engine.status !== 'blocked' || !engine.block) continue;
326	
327	        const blockType = blockTypeRegistry.get(engine.block.type);
328	        if (!blockType) continue; // Type was unregistered after block was created; skip
329	
330	        // Poll interval throttle
331	        if (blockType.pollIntervalMs !== undefined && engine.block.lastCheckedAt) {
332	          const elapsed = Date.now() - new Date(engine.block.lastCheckedAt).getTime();
333	          if (elapsed < blockType.pollIntervalMs) continue;
334	        }
335	
336	        let cleared: boolean;
337	        try {
338	          cleared = await blockType.check(engine.block.condition);
339	        } catch (err) {
340	          // Log warning, skip — engine stays blocked, retry next cycle
341	          console.warn(
342	            `Block checker "${engine.block.type}" threw for engine "${engine.id}" in rig "${rig.id}":`,
343	            err,
344	          );
345	          continue;
346	        }
347	
348	        if (!cleared) {
349	          // Update lastCheckedAt and continue checking other engines
350	          const now = new Date().toISOString();
351	          const updatedEngines = rig.engines.map((e) =>
352	            e.id === engine.id
353	              ? { ...e, block: { ...e.block!, lastCheckedAt: now } }
354	              : e,
355	          );
356	          await rigsBook.patch(rig.id, { engines: updatedEngines });
357	          continue; // Check next engine
358	        }
359	
360	        // Cleared — store block record in memory for priorBlock, then transition engine to pending
361	        const priorBlockRecord = engine.block;
362	        pendingPriorBlocks.set(`${rig.id}:${engine.id}`, priorBlockRecord);
363	
364	        const updatedEngines = rig.engines.map((e) =>
365	          e.id === engine.id
366	            ? { ...e, status: 'pending' as const, block: undefined }
367	            : e,
368	        );
369	
370	        // Restore rig to running if it was blocked; use isRigBlocked on updatedEngines
371	        // (always false after unblocking, but keeps call sites consistent per R13)
372	        const stillBlocked = isRigBlocked(updatedEngines);
373	        const rigStatus = stillBlocked ? 'blocked' : 'running';
374	
375	        await rigsBook.patch(rig.id, {
376	          engines: updatedEngines,
377	          status: rigStatus,
378	        });
379	
380	        return { action: 'engine-unblocked', rigId: rig.id, engineId: engine.id };
381	      }
382	    }
383	    return null;
384	  }
385	
386	  /**
387	   * Phase 3 — run.
388	   *
389	   * Find the first pending engine in any running rig whose upstream is
390	   * all completed. Execute it:
391	   * - Clockwork ('completed') → store yields, mark engine completed,
392	   *   check for rig completion.
393	   * - Quick ('launched') → store sessionId, mark engine running.
394	   * - Blocked ('blocked') → validate block type and condition, persist
395	   *   block record, check whether rig should enter blocked state.
396	   */
397	  async function tryRun(): Promise<CrawlResult | null> {
398	    const runningRigs = await rigsBook.find({ where: [['status', '=', 'running']] });
399	    for (const rig of runningRigs) {
400	      const pending = findRunnableEngine(rig);
401	      if (!pending) continue;
402	
403	      const design = fabricator.getEngineDesign(pending.designId);
404	      if (!design) {
405	        await failEngine(rig, pending.id, `No engine design found for "${pending.designId}"`);
406	        return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
407	      }
408	
409	      const now = new Date().toISOString();
410	      const upstream = buildUpstreamMap(rig);
411	      const givens = { ...pending.givensSpec };
412	
413	      // Check for a prior block record (engine was previously blocked and unblocked)
414	      const priorBlockKey = `${rig.id}:${pending.id}`;
415	      const priorBlock = pendingPriorBlocks.get(priorBlockKey);
416	      if (priorBlock) pendingPriorBlocks.delete(priorBlockKey);
417	
418	      const context = {
419	        engineId: pending.id,
420	        upstream,
421	        ...(priorBlock ? { priorBlock } : {}),
422	      };
423	
424	      let engineResult: Awaited<ReturnType<typeof design.run>>;
425	      try {
426	        // Mark engine as running before executing
427	        const startedEngines = rig.engines.map((e) =>
428	          e.id === pending.id ? { ...e, status: 'running' as const, startedAt: now } : e,
429	        );
430	        await rigsBook.patch(rig.id, { engines: startedEngines });
431	
432	        // Re-fetch to get the up-to-date engines list (with startedAt set)
433	        const updatedRig = { ...rig, engines: startedEngines };
434	
435	        engineResult = await design.run(givens, context);
436	
437	        if (engineResult.status === 'launched') {
438	          // Quick engine — store sessionId, leave engine in 'running'
439	          const { sessionId } = engineResult;
440	          const launchedEngines = updatedRig.engines.map((e) =>
441	            e.id === pending.id
442	              ? { ...e, status: 'running' as const, sessionId }
443	              : e,
444	          );
445	          await rigsBook.patch(rig.id, { engines: launchedEngines });
446	          return { action: 'engine-started', rigId: rig.id, engineId: pending.id };
447	        }
448	
449	        if (engineResult.status === 'blocked') {
450	          const { blockType: blockTypeId, condition, message } = engineResult;
451	
452	          // Look up the block type
453	          const blockType = blockTypeRegistry.get(blockTypeId);
454	          if (!blockType) {
455	            await failEngine(updatedRig, pending.id, `Unknown block type: "${blockTypeId}"`);
456	            return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
457	          }
458	
459	          // Validate the condition against the block type's schema
460	          try {
461	            blockType.conditionSchema.parse(condition);
462	          } catch (zodErr) {
463	            const zodMessage = zodErr instanceof Error ? zodErr.message : String(zodErr);
464	            await failEngine(
465	              updatedRig,
466	              pending.id,
467	              `Block type "${blockTypeId}" rejected condition: ${zodMessage}`,
468	            );
469	            return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
470	          }
471	
472	          // Build the block record and persist the blocked engine
473	          const blockRecord: BlockRecord = {
474	            type: blockTypeId,
475	            condition,
476	            blockedAt: new Date().toISOString(),
477	            ...(message !== undefined ? { message } : {}),
478	          };
479	
480	          const blockedEngines = updatedRig.engines.map((e) =>
481	            e.id === pending.id
482	              ? { ...e, status: 'blocked' as const, block: blockRecord }
483	              : e,
484	          );
485	
486	          // Determine whether the rig should also enter blocked state
487	          if (isRigBlocked(blockedEngines)) {
488	            await rigsBook.patch(rig.id, { engines: blockedEngines, status: 'blocked' });
489	            return { action: 'rig-blocked', rigId: rig.id, writId: rig.writId };
490	          }
491	
492	          await rigsBook.patch(rig.id, { engines: blockedEngines });
493	          return { action: 'engine-blocked', rigId: rig.id, engineId: pending.id, blockType: blockTypeId };
494	        }
495	
496	        // Clockwork engine — validate and store yields
497	        const { yields } = engineResult;
498	        if (!isJsonSerializable(yields)) {
499	          await failEngine(updatedRig, pending.id, 'Engine yields are not JSON-serializable');
500	          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
501	        }
502	
503	        const completedAt = new Date().toISOString();
504	        const completedEngines = updatedRig.engines.map((e) =>
505	          e.id === pending.id
506	            ? { ...e, status: 'completed' as const, yields, completedAt }
507	            : e,
508	        );
509	        const allCompleted = completedEngines.every((e) => e.status === 'completed');
510	        await rigsBook.patch(rig.id, {
511	          engines: completedEngines,
512	          status: allCompleted ? 'completed' : 'running',
513	        });
514	
515	        if (allCompleted) {
516	          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'completed' };
517	        }
518	        return { action: 'engine-completed', rigId: rig.id, engineId: pending.id };
519	      } catch (err) {
520	        const errorMessage = err instanceof Error ? err.message : String(err);
521	        await failEngine(rig, pending.id, errorMessage);
522	        return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
523	      }
524	    }
525	    return null;
526	  }
527	
528	  /**
529	   * Phase 4 — spawn.
530	   *
531	   * Find the oldest ready writ with no existing rig. Create a rig and
532	   * transition the writ to active so the Clerk tracks it as in-progress.
533	   */
534	  async function trySpawn(): Promise<CrawlResult | null> {
535	    // Find ready writs ordered by creation time (oldest first)
536	    const readyWrits = await writsBook.find({
537	      where: [['status', '=', 'ready']],
538	      orderBy: ['createdAt', 'asc'],
539	      limit: 10,
540	    });
541	
542	    for (const writ of readyWrits) {
543	      // Check for existing rig
544	      const existing = await rigsBook.find({
545	        where: [['writId', '=', writ.id]],
546	        limit: 1,
547	      });
548	      if (existing.length > 0) continue;
549	
550	      const rigId = generateId('rig', 4);
551	      const engines = buildStaticEngines(writ, spiderConfig);
552	
553	      const rig: RigDoc = {
554	        id: rigId,
555	        writId: writ.id,
556	        status: 'running',
557	        engines,
558	        createdAt: new Date().toISOString(),
559	      };
560	
561	      await rigsBook.put(rig);
562	
563	      // Transition writ to active so Clerk tracks it
564	      try {
565	        await clerk.transition(writ.id, 'active');
566	      } catch (err) {
567	        // Only swallow state-transition conflicts (writ already moved past 'ready')
568	        if (err instanceof Error && err.message.includes('transition')) {
569	          // Race condition — another spider got here first. The rig is already created,
570	          // so we continue. The writ is already active or beyond.
571	        } else {
572	          throw err;
573	        }
574	      }
575	
576	      return { action: 'rig-spawned', rigId, writId: writ.id };
577	    }
578	
579	    return null;
580	  }
581	
582	  // ── SpiderApi ─────────────────────────────────────────────────────
583	
584	  const api: SpiderApi = {
585	    async crawl(): Promise<CrawlResult | null> {
586	      const collected = await tryCollect();
587	      if (collected) return collected;
588	
589	      const checked = await tryCheckBlocked();
590	      if (checked) return checked;
591	
592	      const ran = await tryRun();
593	      if (ran) return ran;
594	
595	      const spawned = await trySpawn();
596	      if (spawned) return spawned;
597	
598	      return null;
599	    },
600	
601	    async show(id: string): Promise<RigDoc> {
602	      const results = await rigsBook.find({ where: [['id', '=', id]], limit: 1 });
603	      if (results.length === 0) {
604	        throw new Error(`Rig "${id}" not found.`);
605	      }
606	      return results[0];
607	    },
608	
609	    async list(filters?: RigFilters): Promise<RigDoc[]> {
610	      const where: WhereClause = [];
611	      if (filters?.status !== undefined) {
612	        where.push(['status', '=', filters.status]);
613	      }
614	      const limit = filters?.limit ?? 20;
615	      return rigsBook.find({
616	        where,
617	        orderBy: ['createdAt', 'desc'],
618	        limit,
619	        ...(filters?.offset !== undefined ? { offset: filters.offset } : {}),
620	      });
621	    },
622	
623	    async forWrit(writId: string): Promise<RigDoc | null> {
624	      const results = await rigsBook.find({ where: [['writId', '=', writId]], limit: 1 });
625	      return results[0] ?? null;
626	    },
627	
628	    async resume(rigId: string, engineId: string): Promise<void> {
629	      const rig = await api.show(rigId); // Throws if not found
630	      const engine = rig.engines.find((e) => e.id === engineId);
631	      if (!engine) {
632	        throw new Error(`Engine "${engineId}" not found in rig "${rigId}".`);
633	      }
634	      if (engine.status !== 'blocked') {
635	        throw new Error(
636	          `Engine "${engineId}" in rig "${rigId}" is not blocked (status: ${engine.status}).`,
637	        );
638	      }
639	
640	      // Store prior block for priorBlock context on next run
641	      if (engine.block) {
642	        pendingPriorBlocks.set(`${rigId}:${engineId}`, engine.block);
643	      }
644	
645	      const updatedEngines = rig.engines.map((e) =>
646	        e.id === engineId
647	          ? { ...e, status: 'pending' as const, block: undefined }
648	          : e,
649	      );
650	
651	      const rigStatus = rig.status === 'blocked' ? 'running' : rig.status;
652	
653	      await rigsBook.patch(rigId, {
654	        engines: updatedEngines,
655	        status: rigStatus,
656	      });
657	    },
658	
659	    getBlockType(id: string): BlockType | undefined {
660	      return blockTypeRegistry.get(id);
661	    },
662	  };
663	
664	  // ── Apparatus ─────────────────────────────────────────────────────
665	
666	  return {
667	    apparatus: {
668	      requires: ['stacks', 'clerk', 'fabricator'],
669	      consumes: ['blockTypes'],
670	
671	      supportKit: {
672	        books: {
673	          rigs: {
674	            indexes: ['status', 'writId', ['status', 'writId'], 'createdAt'],
675	          },
676	        },
677	        engines: {
678	          draft:     draftEngine,
679	          implement: implementEngine,
680	          review:    reviewEngine,
681	          revise:    reviseEngine,
682	          seal:      sealEngine,
683	        },
684	        blockTypes: {
685	          'writ-status':    writStatusBlockType,
686	          'scheduled-time': scheduledTimeBlockType,
687	          'book-updated':   bookUpdatedBlockType,
688	        },
689	        tools: [crawlOneTool, crawlContinualTool, rigShowTool, rigListTool, rigForWritTool, rigResumeTool],
690	      },
691	
692	      provides: api,
693	
694	      start(ctx: StartupContext): void {
695	        const g = guild();
696	        spiderConfig = g.guildConfig().spider ?? {};
697	
698	        const stacks = g.apparatus<StacksApi>('stacks');
699	        clerk = g.apparatus<ClerkApi>('clerk');
700	        fabricator = g.apparatus<FabricatorApi>('fabricator');
701	
702	        rigsBook = stacks.book<RigDoc>('spider', 'rigs');
703	        sessionsBook = stacks.readBook<SessionDoc>('animator', 'sessions');
704	        writsBook = stacks.readBook<WritDoc>('clerk', 'writs');
705	
706	        // Scan all already-loaded kits for block types.
707	        // These fired plugin:initialized before any apparatus started.
708	        for (const kit of g.kits()) {
709	          blockTypeRegistry.register(kit);
710	        }
711	
712	        // Subscribe to plugin:initialized for apparatus supportKits that
713	        // fire after us in the startup sequence.
714	        ctx.on('plugin:initialized', (plugin: unknown) => {
715	          const loaded = plugin as LoadedPlugin;
716	          if (isLoadedApparatus(loaded)) {
717	            blockTypeRegistry.register(loaded);
718	          }
719	        });
720	
721	        // CDC — Phase 1 cascade on rigs book.
722	        // When a rig reaches a terminal state, transition the associated writ.
723	        // The 'blocked' status intentionally falls through — no CDC action.
724	        stacks.watch<RigDoc>(
725	          'spider',
726	          'rigs',
727	          async (event) => {
728	            if (event.type !== 'update') return;
729	
730	            const rig = event.entry;
731	            const prev = event.prev;
732	
733	            // Only act when status changes to a terminal state
734	            if (rig.status === prev.status) return;
735	
736	            if (rig.status === 'completed') {
737	              // Use seal yields as the resolution summary
738	              const sealEngine = rig.engines.find((e) => e.id === 'seal');
739	              const resolution = sealEngine?.yields
740	                ? JSON.stringify(sealEngine.yields)
741	                : 'Rig completed';
742	              await clerk.transition(rig.writId, 'completed', { resolution });
743	            } else if (rig.status === 'failed') {
744	              const failedEngine = rig.engines.find((e) => e.status === 'failed');
745	              const resolution = failedEngine?.error ?? 'Engine failure';
746	              await clerk.transition(rig.writId, 'failed', { resolution });
747	            }
748	            // 'blocked' status — no CDC action, writ stays in current state
749	          },
750	          { failOnError: true },
751	        );
752	      },
753	    },
754	  };
755	}
