2	 * Built-in block type: scheduled-time.
3	 *
4	 * Blocks until a specified ISO 8601 timestamp is reached.
5	 * Condition: { resumeAt: string }
6	 */
7	
8	import { z } from 'zod';
9	import type { BlockType } from '../types.ts';
10	
11	const conditionSchema = z.object({
12	  resumeAt: z.string(),
13	});
