      engines: [
        { id: 'draft',     designId: 'draft',     givens: { writ: '$writ' } },
        { id: 'implement', designId: 'implement', upstream: ['draft'],     givens: { writ: '$writ', role: '$role' } },
        { id: 'review',    designId: 'review',    upstream: ['implement'], givens: { writ: '$writ' } },
